import JobSelection from "../components/JobSelection";
import {
  AlertCircle,
  Briefcase,
  ArrowRight,
  Loader2
} from "lucide-react";
import { useState } from "react";
import { Link } from "react-router-dom";
import { useAuth } from "../src/context/AuthContext";
import axios from "axios"; // Assuming axios is installed and needed for the new API call

export default function Analyze() {
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const { globalResume } = useAuth();

  const handleAnalyze = async (selectedJobId) => {
    if (!selectedJobId) {
      setError("Please select a job first.");
      return;
    }

    setLoading(true);
    setError(null);
    setResults(null);

    try {
      if (!globalResume) {
        setError("No resume found in your session. Please log in again.");
        setLoading(false);
        return;
      }

      const formData = new FormData();
      formData.append("resume", globalResume);
      formData.append("job_desc_id", selectedJobId);

      const res = await axios.post("http://127.0.0.1:8000/api/score/", formData, {
        headers: { "Content-Type": "multipart/form-data" }
      });

      setResults(res.data);
    } catch (err) {
      console.error(err);
      setError(
        err.response?.data?.error || "Error analyzing resume. Please try again."
      );
    } finally {
      setLoading(false);
    }
  };

  const getScoreColor = (score) => {
    if (score >= 80) return "text-green-600 bg-green-50 border-green-100";
    if (score >= 60) return "text-blue-600 bg-blue-50 border-blue-100";
    if (score >= 40) return "text-yellow-600 bg-yellow-50 border-yellow-100";
    return "text-red-600 bg-red-50 border-red-100";
  };

  return (
    <section className="bg-gray-50 min-h-screen py-16">
      <div className="max-w-5xl mx-auto px-6">
        <div className="text-center mb-12">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            Find Your Perfect Job Match
          </h1>
          <p className="text-gray-600">
            Upload your resume to see which open positions you are most compatible with.
          </p>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 mb-12">
           {globalResume ? (
              <div className="flex items-center gap-3 p-4 bg-indigo-50 text-indigo-700 rounded-xl mb-6 border border-indigo-100">
                  <span className="font-semibold">✓ Resume loaded.</span> We'll use your session resume for analysis.
              </div>
           ) : (
             <div className="flex items-center gap-3 p-4 bg-orange-50 text-orange-700 rounded-xl mb-6 border border-orange-100">
                  <span className="font-semibold">⚠ No resume found.</span> <Link to="/login?role=candidate" className="underline font-bold">Please click here to upload your resume.</Link>
              </div>
           )}
          
          <JobSelection onAnalyze={handleAnalyze} isLoading={loading} />
        </div>

        {/* Results Section */}
        {loading && (
             <div className="text-center py-12">
                <div className="w-12 h-12 mx-auto mb-4 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin" />
                <p className="text-lg text-gray-600 font-medium">Analyzing your resume against active jobs...</p>
             </div>
        )}

        {!loading && results && (
            <div className="animate-fade-in space-y-6">
                <h2 className="text-2xl font-bold text-gray-900 mb-6">Top Matches for You</h2>
                
                {results.length === 0 ? (
                    <div className="text-center py-12 bg-white rounded-2xl shadow-sm">
                        <AlertCircle className="w-12 h-12 mx-auto text-gray-400 mb-4" />
                        <p className="text-gray-600 text-lg">No jobs found matching your profile.</p>
                    </div>
                ) : (
                    <div className="grid gap-6">
                        {results.map((job) => (
                            <div key={job.id} className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition flex flex-col sm:flex-row items-start sm:items-center justify-between gap-6">
                                <div className="flex-1">
                                    <h3 className="text-xl font-bold text-gray-900 mb-1">{job.title}</h3>
                                    <p className="text-gray-500 font-medium flex items-center gap-2">
                                        <Briefcase className="w-4 h-4" />
                                        {job.company}
                                    </p>
                                </div>

                                <div className="flex items-center gap-6 w-full sm:w-auto justify-between sm:justify-end">
                                    <div className={`px-4 py-2 rounded-lg border flex flex-col items-center ${getScoreColor(job.score)}`}>
                                        <span className="text-2xl font-bold">{job.score}%</span>
                                        <span className="text-xs uppercase font-bold tracking-wider">Match</span>
                                    </div>
                                    
                                    <Link 
                                        to={`/jobs/${job.id}`}
                                        className="bg-indigo-600 text-white p-3 rounded-full hover:bg-indigo-700 transition shadow-md"
                                        title="View Job"
                                    >
                                        <ArrowRight className="w-5 h-5" />
                                    </Link>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        )}

      </div>
    </section>
  );
}

import { useState } from "react";
import { Briefcase, Building2, FileText, CheckCircle, AlertCircle, X, Plus } from "lucide-react";

export default function CreateJob() {
  const [title, setTitle] = useState("");
  const [company, setCompany] = useState("");
  const [description, setDescription] = useState("");
  const [minScore, setMinScore] = useState(50);
  const [skills, setSkills] = useState([]);
  const [currentSkill, setCurrentSkill] = useState("");
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);

  const handleAddSkill = (e) => {
    if ((e.key === 'Enter' || e.type === 'click') && currentSkill.trim()) {
      e.preventDefault();
      if (!skills.includes(currentSkill.trim())) {
        setSkills([...skills, currentSkill.trim()]);
      }
      setCurrentSkill("");
    }
  };

  const removeSkill = (skillToRemove) => {
    setSkills(skills.filter(skill => skill !== skillToRemove));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage("");

    try {
      const response = await fetch(
        "http://127.0.0.1:8000/api/ats/jobs/create/",
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            title,
            company_name: company,
            description,
            skills,
            min_score_required: minScore,
          }),
        }
      );

      const data = await response.json();
      
      if (response.ok) {
        setMessage({ type: "success", text: data.message || "Job Created Successfully" });
        setTitle("");
        setCompany("");
        setDescription("");
        setSkills([]);
        setMinScore(50);
      } else {
        setMessage({ type: "error", text: data.error || "Failed to create job" });
      }
    } catch (err) {
      setMessage({ type: "error", text: "Something went wrong. Please try again." });
    } finally {
      setLoading(false);
    }
  };

  return (
    <section className="min-h-screen bg-gray-50 py-12 px-6">
      <div className="max-w-3xl mx-auto">
        <div className="bg-white rounded-2xl shadow-xl overflow-hidden">
          <div className="bg-indigo-600 px-8 py-6 text-white">
            <h1 className="text-2xl font-bold flex items-center gap-2">
              <Briefcase className="w-6 h-6" />
              Post a New Job
            </h1>
            <p className="text-indigo-100 mt-1">Found the perfect candidate? Let's get listed.</p>
          </div>
          
          <div className="p-8">
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Job Title</label>
                  <div className="relative">
                    <Briefcase className="absolute left-3 top-3 w-5 h-5 text-gray-400" />
                    <input
                      type="text"
                      value={title}
                      onChange={(e) => setTitle(e.target.value)}
                      className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition outline-none"
                      placeholder="e.g. Senior Product Designer"
                      required
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Company Name</label>
                  <div className="relative">
                    <Building2 className="absolute left-3 top-3 w-5 h-5 text-gray-400" />
                    <input
                      type="text"
                      value={company}
                      onChange={(e) => setCompany(e.target.value)}
                      className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition outline-none"
                      placeholder="e.g. Acme Corp"
                      required
                    />
                  </div>
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">
                  Job Description
                </label>
                <div className="relative">
                    <FileText className="absolute left-3 top-3 w-5 h-5 text-gray-400" />
                    <textarea
                    rows="6"
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition outline-none resize-none"
                    placeholder="Describe the role, responsibilities, and requirements..."
                    required
                    />
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">
                  Required Skills
                </label>
                <div className="flex gap-2 mb-3">
                    <input
                        type="text"
                        value={currentSkill}
                        onChange={(e) => setCurrentSkill(e.target.value)}
                        onKeyDown={handleAddSkill}
                        className="flex-1 px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition outline-none"
                        placeholder="Type a skill and press Enter (e.g. Python)"
                    />
                    <button 
                        type="button"
                        onClick={handleAddSkill}
                        className="px-4 py-3 bg-gray-100 text-gray-700 rounded-xl hover:bg-gray-200 transition"
                    >
                        <Plus className="w-5 h-5" />
                    </button>
                </div>
                
                <div className="flex flex-wrap gap-2">
                    {skills.map((skill, index) => (
                        <span key={index} className="inline-flex items-center gap-1 px-3 py-1 bg-indigo-50 text-indigo-700 rounded-full text-sm font-medium animate-pop">
                            {skill}
                            <button type="button" onClick={() => removeSkill(skill)} className="hover:text-indigo-900">
                                <X className="w-3 h-3" />
                            </button>
                        </span>
                    ))}
                    {skills.length === 0 && (
                        <p className="text-sm text-gray-400 italic">No skills added yet.</p>
                    )}
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">
                  Minimum ATS Score Required (%)
                </label>
                <input
                    type="range"
                    min="0"
                    max="100"
                    value={minScore}
                    onChange={(e) => setMinScore(e.target.value)}
                    className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                />
                 <div className="flex justify-between text-xs text-gray-500 mt-2 font-medium">
                    <span>0%</span>
                    <span className="text-indigo-600 bg-indigo-50 px-2 py-1 rounded text-sm">{minScore}%</span>
                    <span>100%</span>
                </div>
              </div>

              {message && (
                <div className={`p-4 rounded-xl flex items-center gap-3 ${message.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                    {message.type === 'success' ? <CheckCircle className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}
                    <p className="font-medium">{message.text}</p>
                </div>
              )}

              <button
                type="submit"
                disabled={loading}
                className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold text-lg hover:bg-indigo-700 active:transform active:scale-[0.98] transition shadow-lg shadow-indigo-200 disabled:opacity-70 disabled:cursor-not-allowed"
              >
                {loading ? "Creating..." : "Create Job Posting"}
              </button>
            </form>
          </div>
        </div>
      </div>
    </section>
  );
}

import {
  User,
  Mail,
  FileText,
  GraduationCap,
  Briefcase,
  Download,
  CheckCircle,
} from "lucide-react";
import { useState } from "react";
function Input({ icon: Icon, label, ...props }) {
  return (
    <div>
      <label className="flex items-center gap-2 mb-2 text-sm font-medium">
        <Icon className="w-4 h-4 text-indigo-600" />
        {label}
      </label>
      <input
        {...props}
        className="w-full rounded-xl bg-gray-100 p-4 border border-gray-200"
      />
    </div>
  );
}

function Textarea({ icon: Icon, label, ...props }) {
  return (
    <div>
      <label className="flex items-center gap-2 mb-2 text-sm font-medium">
        <Icon className="w-4 h-4 text-indigo-600" />
        {label}
      </label>
      <textarea
        rows={4}
        {...props}
        className="w-full rounded-xl bg-gray-100 p-4 border border-gray-200"
      />
    </div>
  );
}

export default function Generate() {
  // const API_BASE = "https://resume-ranker-backend-esei.onrender.com";
  const API_BASE = "http://127.0.0.1:8000/";
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    skills: "",
    education: "",
    experience: "",
  });

  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [pdfUrl, setPdfUrl] = useState(null);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };
  const handleGenerate = async () => {
    if (!form.name) {
      alert("Name is required");
      return;
    }

    setLoading(true);
    setSuccess(false);

    try {
      const res = await fetch(`${API_BASE}/api/ats/generate-resume/`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(form),
      });

      if (!res.ok) {
        const errorText = await res.text();
        throw new Error(errorText);
      }

      const contentType = res.headers.get("content-type");
      if (!contentType.includes("application/pdf")) {
        throw new Error("Server did not return a PDF");
      }

      const blob = await res.blob();
      const url = window.URL.createObjectURL(blob);

      setPdfUrl(url);
      setSuccess(true);
    } catch (err) {
      console.error(err);
      alert("Resume generation failed");
    } finally {
      setLoading(false);
    }
  };
  return (
    <section className="bg-gray-50 min-h-screen py-16">
      <div className="max-w-4xl mx-auto px-6">
        <div className="text-center mb-10">
          <h1 className="text-3xl font-bold">Resume Generator</h1>
          <p className="text-gray-600">
            Generate an ATS-optimized resume from your information
          </p>
        </div>

        <div className="bg-white rounded-2xl p-8 shadow-sm space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Input
              icon={User}
              label="Full Name"
              name="name"
              value={form.name}
              onChange={handleChange}
              placeholder="John Doe"
            />
            <Input
              icon={Mail}
              label="Email Address"
              name="email"
              value={form.email}
              onChange={handleChange}
              placeholder="john@example.com"
            />
          </div>

          <Input
            icon={User}
            label="Phone Number"
            name="phone"
            value={form.phone}
            onChange={handleChange}
            placeholder="+91 98765 43210"
          />

          <Textarea
            icon={FileText}
            label="Skills"
            name="skills"
            value={form.skills}
            onChange={handleChange}
            placeholder="Python, Machine Learning, SQL, Docker..."
          />
          <Textarea
            icon={GraduationCap}
            label="Education"
            name="education"
            value={form.education}
            onChange={handleChange}
            placeholder="B.Tech in Computer Engineering, XYZ University"
          />
          <Textarea
            icon={Briefcase}
            label="Experience"
            name="experience"
            value={form.experience}
            onChange={handleChange}
            placeholder="Software Engineering Intern at ABC Corp..."
          />

          <div className="flex flex-col md:flex-row gap-4 pt-4">
            <button
              onClick={handleGenerate}
              disabled={loading}
              className="flex-1 py-4 rounded-xl bg-indigo-600 text-white font-semibold hover:bg-indigo-700 transition flex items-center justify-center gap-2"
            >
              {loading ? "Generating..." : "Generate ATS-Friendly Resume"}
            </button>

            {pdfUrl && (
              <a
                href={pdfUrl}
                download="ATS_Resume.pdf"
                className="flex-1 py-4 rounded-xl border border-indigo-200 font-semibold flex items-center justify-center gap-2 hover:bg-indigo-50"
              >
                <Download className="w-4 h-4" />
                Download Resume
              </a>
            )}
          </div>

          {success && (
            <div className="mt-6 flex gap-3 p-4 rounded-xl bg-green-50 border border-green-200 text-green-700">
              <CheckCircle className="w-5 h-5 mt-0.5 text-green-600" />

              <div>
                <p className="font-medium">Resume Generated Successfully!</p>
                <p className="text-sm">
                  Your ATS-optimized resume is ready. Click the download button
                  to save it.
                </p>
              </div>
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

