import { createContext, useContext, useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const navigate = useNavigate();
  // Role string ("candidate" or "company")
  const [role, setRole] = useState(() => localStorage.getItem("role") || null);
  
  // Stored resume file to use everywhere
  const [globalResume, setGlobalResume] = useState(null);

  const login = (selectedRole, storedFile = null) => {
    setRole(selectedRole);
    localStorage.setItem("role", selectedRole);
    if (storedFile) {
        setGlobalResume(storedFile);
    }
  };

  const logout = () => {
    setRole(null);
    setGlobalResume(null);
    localStorage.removeItem("role");
    navigate("/");
  };

  return (
    <AuthContext.Provider value={{ role, login, logout, globalResume, setGlobalResume }}>
      {children}
    </AuthContext.Provider>
  );
};

// eslint-disable-next-line react-refresh/only-export-components
export const useAuth = () => useContext(AuthContext);

